</div>
<div id="v11-render-target"></div>

<script>
(function() {
    const rawDataEl = document.querySelector('#v11-raw-data');
    const renderTarget = document.querySelector('#v11-render-target');
    if (!rawDataEl || !renderTarget || renderTarget.innerHTML !== '') return;

    const rawText = rawDataEl.textContent.trim();

    // 数据提取
    const extractBlock = (text, tag) => {
        const regex = new RegExp(`\\[${tag}\\]([\\s\\S]*?)\\[\\/${tag}\\]`, 'i');
        const match = text.match(regex);
        return match ? match[1].trim() : '';
    };
    const extractMultiBlocks = (text, tag) => {
        const regex = new RegExp(`\\[${tag}\\]([\\s\\S]*?)\\[\\/${tag}\\]`, 'gi');
        let matches = [];
        let match;
        while ((match = regex.exec(text)) !== null) matches.push(match[1].trim());
        return matches;
    };
    const parseKeyValue = (text) => {
        let obj = {};
        const lines = text.split('\n');
        lines.forEach(line => {
            const index = line.indexOf(':');
            const index2 = line.indexOf('：');
            let splitIdx = -1;
            if (index !== -1 && index2 !== -1) splitIdx = Math.min(index, index2);
            else if (index !== -1) splitIdx = index;
            else if (index2 !== -1) splitIdx = index2;
            if(splitIdx !== -1) {
                const key = line.substring(0, splitIdx).trim();
                const val = line.substring(splitIdx + 1).trim();
                if(key) obj[key] = val;
            }
        });
        return obj;
    };

    const sceneObj = parseKeyValue(extractBlock(rawText, '场景'));
    const charsData = extractMultiBlocks(rawText, '角色').map(parseKeyValue);
    const gearObj = parseKeyValue(extractBlock(rawText, '行囊'));
    const bondObj = parseKeyValue(extractBlock(rawText, '羁绊'));
    const theaterObj = parseKeyValue(extractBlock(rawText, '剧场'));
    const musicObj = parseKeyValue(extractBlock(rawText, '音乐'));
    const danmakuText = extractBlock(rawText, '弹幕');
    let danmakuArr = danmakuText ? danmakuText.replace('内容:', '').replace('内容：', '').split(/[,，]/).map(s=>s.trim()).filter(Boolean) : [];

    const musicTitle = musicObj['歌名'] || '未名旋律';
    const musicArtist = musicObj['歌手'] || '星空投影';

    // 生成HTML
    let html = `
    <div class="cosmos-glass-container" id="glass-ui-box">
        <div class="glass-player-island">
            <!-- MAC风格颜色切换小圆点 -->
            <div class="mac-dots-wrap">
                <div class="mac-dot dot-c1" data-color="#c4a79c" data-light="rgba(196,167,156,0.2)" title="玫瑰流沙"></div>
                <div class="mac-dot dot-c2" data-color="#8da3af" data-light="rgba(141,163,175,0.2)" title="灰雾苍蓝"></div>
                <div class="mac-dot dot-c3" data-color="#b5c4b1" data-light="rgba(181,196,177,0.2)" title="晨曦茶白"></div>
                <div class="mac-dot dot-c4" data-color="#b0a3c4" data-light="rgba(176,163,196,0.2)" title="暮夜丁香"></div>
            </div>

            <div class="island-main-row">
                <div class="island-cover" id="island-cover-box">
                    <img id="island-img" src="" alt="cover">
                </div>
                <div class="island-info">
                    <div class="island-title" id="music-title">${musicTitle}</div>
                    <div class="island-artist" id="music-artist">${musicArtist}</div>
                </div>
                <div class="island-controls">
                    <button class="island-btn" id="btn-play-pause">
                        <svg id="icon-play" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
                        <svg id="icon-pause" viewBox="0 0 24 24" style="display:none;"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/></svg>
                    </button>
                    <button class="island-btn" id="btn-refresh">
                        <svg viewBox="0 0 24 24"><path d="M17.65 6.35C16.2 4.9 14.21 4 12 4c-4.42 0-7.99 3.58-7.99 8s3.57 8 7.99 8c3.73 0 6.84-2.55 7.73-6h-2.08c-.82 2.33-3.04 4-5.65 4-3.31 0-6-2.69-6-6s2.69-6 6-6c1.66 0 3.14.69 4.22 1.78L13 11h7V4l-2.35 2.35z"/></svg>
                    </button>
                </div>
            </div>
            <div class="island-lyrics-wrap" id="island-lyrics-wrap"></div>
            <audio class="island-audio-core" id="island-audio" preload="metadata"></audio>
        </div>

        <div class="glass-nav">
            <div class="glass-tab active" data-tab="scene">SCENE</div>
            <div class="glass-tab" data-tab="char">MIND</div>
            <div class="glass-tab" data-tab="gear">GEAR</div>
            <div class="glass-tab" data-tab="bond">BOND</div>
            <div class="glass-tab" data-tab="theater">THEATER</div>
            <div class="glass-tab" data-tab="dmk">ECHO</div>
        </div>

        <div class="glass-content-area">
            <div class="glass-panel active" id="panel-scene">
                ${Object.keys(sceneObj).map(k => `
                    <div class="glass-item"><span class="glass-label">${k}</span><span class="glass-val">${sceneObj[k]}</span></div>
                `).join('')}
                ${musicObj['氛围'] ? `<div class="glass-item"><span class="glass-label">氛围</span><span class="glass-val" style="color:var(--accent-color); font-style:italic;">${musicObj['氛围']}</span></div>` : ''}
            </div>

            <div class="glass-panel" id="panel-char">
                <div class="char-pills">
                    ${charsData.map((c, i) => `<div class="char-pill ${i===0?'active':''}" data-index="${i}">${c['姓名']||'Unknown'}</div>`).join('')}
                </div>
                <div class="char-content-wrap">
                    ${charsData.map((c, i) => `
                        <div class="char-detail ${i===0?'active':''}" id="char-detail-${i}">
                            ${c['好感'] ? `<div class="glass-item"><span class="glass-label">好感</span><span class="glass-val">${c['好感']}</span></div>` : ''}
                            <div class="glass-item"><span class="glass-label">状态</span><span class="glass-val">${c['状态']||''}</span></div>
                            <div class="glass-mind-bubble">${c['心声']||''}</div>
                        </div>
                    `).join('')}
                </div>
            </div>

            <div class="glass-panel" id="panel-gear">
                ${Object.keys(gearObj).length > 0 ? Object.keys(gearObj).map(k => `
                    <div class="glass-item"><span class="glass-label">${k}</span><span class="glass-val">${gearObj[k]}</span></div>
                `).join('') : '<div style="text-align:center; opacity:0.5; margin-top:20px;">空空如也</div>'}
            </div>

            <div class="glass-panel" id="panel-bond">
                ${Object.keys(bondObj).length > 0 ? Object.keys(bondObj).map(k => `
                    <div class="glass-item"><span class="glass-label">${k}</span><span class="glass-val">${bondObj[k]}</span></div>
                `).join('') : '<div style="text-align:center; opacity:0.5; margin-top:20px;">羁绊未明</div>'}
            </div>

            <div class="glass-panel" id="panel-theater">
                <div class="theater-title">✦ ${theaterObj['标题'] || '未定名的片段'} ✦</div>
                <div class="theater-content">${theaterObj['演绎'] || '帷幕尚未拉开...'}</div>
            </div>

            <div class="glass-panel" id="panel-dmk">
                <div class="glass-danmaku-box" id="v11-dmk-screen"></div>
            </div>
        </div>
    </div>
    `;
    renderTarget.innerHTML = html;

    const container = renderTarget.querySelector('#glass-ui-box');

    // --- MAC 变色小圆点逻辑 ---
    const macDots = container.querySelectorAll('.mac-dot');
    macDots.forEach(dot => {
        dot.addEventListener('click', () => {
            const color = dot.getAttribute('data-color');
            const light = dot.getAttribute('data-light');
            container.style.setProperty('--accent-color', color);
            container.style.setProperty('--accent-light', light);
        });
    });

    // --- Tab 切换逻辑 ---
    const tabs = container.querySelectorAll('.glass-tab');
    const panels = container.querySelectorAll('.glass-panel');
    tabs.forEach(tab => {
        tab.addEventListener('click', () => {
            tabs.forEach(t => t.classList.remove('active'));
            panels.forEach(p => p.classList.remove('active'));
            tab.classList.add('active');

            const targetPanel = container.querySelector(`#panel-${tab.dataset.tab}`);
            targetPanel.classList.add('active');
            targetPanel.scrollTop = 0;

            if(tab.dataset.tab === 'dmk') {
                startDanmaku();
            } else {
                stopDanmaku();
            }
        });
    });

    // --- 角色切换逻辑 ---
    const charPills = container.querySelectorAll('.char-pill');
    const charDetails = container.querySelectorAll('.char-detail');
    charPills.forEach(pill => {
        pill.addEventListener('click', () => {
            charPills.forEach(p => p.classList.remove('active'));
            charDetails.forEach(d => d.classList.remove('active'));
            pill.classList.add('active');
            container.querySelector(`#char-detail-${pill.dataset.index}`).classList.add('active');
        });
    });

    // --- 弹幕逻辑 ---
    let dmkTimeouts = [];
    let dmkInterval = null;
    let isDmkRunning = false;
    const dmkScreen = container.querySelector('#v11-dmk-screen');

    function startDanmaku() {
        if(isDmkRunning || !dmkScreen || danmakuArr.length === 0) return;

        dmkScreen.innerHTML = '';
        isDmkRunning = true;
        const numLanes = 5;
        const containerHeight = dmkScreen.clientHeight || 200;
        const laneHeight = containerHeight / numLanes;

        const createDmk = (text, delay=0) => {
            const tId = setTimeout(() => {
                if(!isDmkRunning || !dmkScreen) return;
                const el = document.createElement('div');
                el.className = 'glass-dmk-item';
                el.textContent = text;

                const lane = Math.floor(Math.random() * numLanes);
                el.style.top = `${lane * laneHeight + 10}px`;
                el.style.animationDuration = `${Math.random() * 4 + 6}s`;

                el.addEventListener('animationend', () => el.remove());
                dmkScreen.appendChild(el);
            }, delay);
            dmkTimeouts.push(tId);
        };

        for(let i=0; i<Math.min(danmakuArr.length, 3); i++) {
            createDmk(danmakuArr[i], i*600);
        }

        let idx = 3;
        dmkInterval = setInterval(() => {
            if(!isDmkRunning) return;
            createDmk(danmakuArr[idx % danmakuArr.length]);
            idx++;
        }, 1800);
    }

    function stopDanmaku() {
        isDmkRunning = false;
        clearInterval(dmkInterval);
        dmkTimeouts.forEach(clearTimeout);
        dmkTimeouts = [];
        if(dmkScreen) dmkScreen.innerHTML = '';
    }

    // --- 幻像灵匣 (音乐播放器) ---
    const audio = container.querySelector('#island-audio');
    const playPauseBtn = container.querySelector('#btn-play-pause');
    const refreshBtn = container.querySelector('#btn-refresh');
    const iconPlay = container.querySelector('#icon-play');
    const iconPause = container.querySelector('#icon-pause');
    const coverBox = container.querySelector('#island-cover-box');
    const coverImg = container.querySelector('#island-img');
    const lyricsWrap = container.querySelector('#island-lyrics-wrap');

    const preciseKeyword = musicTitle + " " + musicArtist;
    let parsedLyrics = [];

    playPauseBtn.addEventListener('click', () => {
        if(!audio.src) { fetchMusic(); return; }
        if(audio.paused) audio.play();
        else audio.pause();
    });

    audio.addEventListener('play', () => {
        iconPlay.style.display = 'none';
        iconPause.style.display = 'block';
        coverBox.classList.add('playing');
    });
    audio.addEventListener('pause', () => {
        iconPlay.style.display = 'block';
        iconPause.style.display = 'none';
        coverBox.classList.remove('playing');
    });

    refreshBtn.addEventListener('click', () => fetchMusic());

    function parseLrc(lrc) {
        const lines = lrc.split('\n');
        const parsed = [];
        lines.forEach(line => {
            let text = line.replace(/\[.*?\]/g, '').trim();
            if (!text) return;
            const timeTags = [...line.matchAll(/\[(\d{2,}):(\d{2})(?:\.(\d{2,3}))?\]/g)];
            timeTags.forEach(m => {
                const min = parseInt(m[1]), sec = parseInt(m[2]), msVal = m[3] || '0';
                const ms = msVal.length === 2 ? parseInt(msVal)*10 : (msVal.length === 1 ? parseInt(msVal)*100 : parseInt(msVal));
                parsed.push({ time: min * 60 + sec + ms / 1000, text });
            });
        });
        return parsed.sort((a,b) => a.time - b.time);
    }

    function setupLyrics(lrcString) {
        if(!lrcString) return;
        parsedLyrics = parseLrc(lrcString);
        lyricsWrap.innerHTML = '';
        if(parsedLyrics.length > 0) {
            parsedLyrics.forEach((lyric, idx) => {
                const p = document.createElement('div');
                p.className = 'island-lyric-line';
                p.id = 'lyric-' + idx;
                p.innerText = lyric.text;
                lyricsWrap.appendChild(p);
            });
        } else {
            const clean = lrcString.replace(/\[.*?\]/g, '').replace(/\n\s*\n/g, '\n').trim();
            if(clean) {
                const p = document.createElement('div');
                p.className = 'island-lyric-line active';
                p.innerText = clean.split('\n')[0];
                lyricsWrap.appendChild(p);
            }
        }
    }

    audio.addEventListener('timeupdate', () => {
        if(!parsedLyrics.length) return;
        const ct = audio.currentTime;
        let activeIdx = -1;
        for(let i = 0; i < parsedLyrics.length; i++) {
            if(ct >= parsedLyrics[i].time - 0.2) activeIdx = i; else break;
        }
        if(activeIdx !== -1) {
            const oldActive = lyricsWrap.querySelector('.island-lyric-line.active');
            if(oldActive && oldActive.id === 'lyric-' + activeIdx) return;
            if(oldActive) oldActive.classList.remove('active');
            const newActive = lyricsWrap.querySelector('#lyric-' + activeIdx);
            if(newActive) newActive.classList.add('active');
        }
    });

    async function fetchMusic() {
        if(musicTitle.includes("{{") || !musicTitle) {
            lyricsWrap.innerHTML = '<div class="island-lyric-line active">未听清旋律的名字...</div>';
            return;
        }
        audio.pause(); audio.src = ''; parsedLyrics = []; lyricsWrap.innerHTML = '';
        coverBox.classList.remove('loaded', 'playing');
        container.style.removeProperty('--cmb-cover-bg');
        coverImg.src = '';
        lyricsWrap.innerHTML = '<div class="island-lyric-line active">探寻星海弦音中...</div>';

        try {
            const r1 = await fetch(`https://music-api.gdstudio.xyz/api.php?types=search&name=${encodeURIComponent(preciseKeyword)}&count=1&pages=1&_t=${Date.now()}`);
            const data = await r1.json();
            if(data && data[0] && data[0].id) {
                const r2 = await fetch(`https://music-api.gdstudio.xyz/api.php?types=url&id=${data[0].id}&br=128000`);
                const d2 = await r2.json();
                if(d2 && d2.url) audio.src = d2.url;

                fetch(`https://music-api.gdstudio.xyz/api.php?types=lyric&id=${data[0].id}`)
                    .then(res => res.json())
                    .then(d => { if(d && d.lyric) setupLyrics(d.lyric); })
                    .catch(e => {});
            }

            let finalPic = data?.[0]?.pic || '';
            try {
                const sr = await fetch(`https://itunes.apple.com/search?term=${encodeURIComponent(preciseKeyword)}&entity=song&limit=1`);
                const sd = await sr.json();
                if(sd?.results?.[0]?.artworkUrl100) {
                    finalPic = sd.results[0].artworkUrl100.replace('100x100bb', '600x600bb');
                }
            } catch(e) {}

            if(finalPic) {
                coverImg.onload = () => {
                    coverBox.classList.add('loaded');
                    container.style.setProperty('--cmb-cover-bg', `url('${finalPic}')`);
                };
                coverImg.src = finalPic;
            }
            if(!audio.src) lyricsWrap.innerHTML = '<div class="island-lyric-line active">星海暗流涌动，序列未能连结。</div>';
        } catch(e) {
            lyricsWrap.innerHTML = '<div class="island-lyric-line active">星海暗流涌动，序列未能连结。</div>';
        }
    }

    if(musicTitle && !musicTitle.includes("{{")) fetchMusic();
})();
</script>
